var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"탄탄하게 다져진 몸매, 의뢰인 보다 큰 키, 도도하면서도 세련된 분위기.","JPN":"がっちりした体つき、依頼人より高い背、おしゃれでクールな感じ。","ENG":"A strong, fit body. Taller than our client. Looks aloof and unapproachable on the outside.","TWN":"身材好，個子比委託人高，帶有孤傲高尚的氣場。"},"stage":{"bg":"SUMMER_BEACH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"거의 완벽하군요. 몇 가지만 더 확인하면 되겠어요.","JPN":"ほぼ完璧ですね。あと、いくつか確認すればいいだけです。","ENG":"She's almost perfect. We just need to check a couple of more things.","TWN":"近乎完美呢，只需要再確認一兩個條件就可以了。"},"stage":{"bg":"SUMMER_BEACH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"실례지만 혹시 귀하의 사회적인 지위가 어느 정도인지 여쭤봐도 되겠습니까?","JPN":"失礼ですが、あなたの社会的地位がどれくらいなのか、お伺いしてもよろしいですか？","ENG":"I'm sorry, but may I ask how successful you are socially?","TWN":"我可以冒昧地問一下閣下的社會地位嗎？"},"stage":{"bg":"SUMMER_BEACH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"네? 저요? 하하, 제 입으로 말하긴 좀 부끄럽지만 이래봬도 저희 세계에서는 좀 알아주는 최고급 용병이긴 하죠.","JPN":"はい？　私ですか？　ハハ、自分で言うのも恥ずかしいですが、\\nこれでも私が住む世界ではなかなか有名な最高ランクの傭兵なんです。","ENG":"Pardon? Me? Hah hah. I don't want to brag, but I am a first-class mercenary in my world.","TWN":"嗯？我嗎？哈哈，自己說會有點不好意思啦，但別看我這樣，我在我們世界裡可是受到世人認可的頂尖傭兵喔。"},"stage":{"bg":"SUMMER_BEACH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"정부 기관 의뢰도 받는 입장이거든요. 엣헴!","JPN":"政府機関から依頼を受けたりもします。えっへん！","ENG":"I even get jobs from governmental agencies. Ahem!","TWN":"還會收到政府機關的委託呢，欸嘿！"},"stage":{"bg":"SUMMER_BEACH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"후후, 낯선 이의 질문에도 자세히 답해주는 저 상냥함!","JPN":"ふふ、見知らぬ者の質問にも詳しく答えてくれるその優しさ！","ENG":"Hah hah. She's also kind enough to answer strangers' questions!","TWN":"呵呵，對陌生人的提問也予以詳盡的解答，何等溫柔！"},"stage":{"bg":"SUMMER_BEACH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"의뢰는 성공적인 것 같군요. 아주 잘 어울리는 한 쌍이 될 것 같네요.","JPN":"依頼は成功したようですね。とてもお似合いのカップルになりそうです。","ENG":"Mission accomplished! You'll make a wonderful couple.","TWN":"委託圓滿地解決了，你們看起來非常相配呢。"},"stage":{"bg":"SUMMER_BEACH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"다...... 다......","JPN":"あ……あ……","ENG":"Ah... Ah...","TWN":"你……你……"},"stage":{"bg":"SUMMER_BEACH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"왜 그러시죠? 너무 기뻐서 말문이 막히셨나요, 고객님?","JPN":"どうしましたか？　嬉しすぎて言葉を失いましたか、お客様？","ENG":"What’s wrong? Let me guess. You're choking on happiness, aren't you?","TWN":"您怎麼了？您是因為太高興，所以說不出話來了嗎，客人？"},"stage":{"bg":"SUMMER_BEACH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"당신 장님이죠?!! 결정적인 문제가 있잖아!!","JPN":"あなた目が見えないんですか？　決定的な問題があるじゃないですか！","ENG":"Are you blind? Can't you see the problem?","TWN":"你眼瞎了嗎？！！有個決定性的問題吧！！"},"stage":{"bg":"SUMMER_BEACH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"저쪽은 여자라고! 여자!!","JPN":"あの人は女の人です！　女の！！","ENG":"She's a girl! A girl!","TWN":"她是個女的！女的！！"},"stage":{"bg":"SUMMER_BEACH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"네? 딱히 성별에 대한 조건은 없었던 것 같습니다만?","JPN":"はい？　特に性別についての条件はなかったようですが？","ENG":"Pardon? But you didn't specify the sex.","TWN":"嗯？我記得妳在性別方面沒有特別要求呀？"},"stage":{"bg":"SUMMER_BEACH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"무슨 문제라도 있습니까?","JPN":"何か問題でもありますか？","ENG":"Is that a problem?","TWN":"有什麼問題嗎？"},"stage":{"bg":"SUMMER_BEACH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"당연히 큰 문제가 있지! 난 남자가 취향이라고!","JPN":"もちろん大問題です！　私は男の人がよかったんです！","ENG":"Yes, it is! I like men!","TWN":"問題很大好嗎！我喜歡男的！"},"stage":{"bg":"SUMMER_BEACH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"하하...... 그나저나 저도 궁금한 게 있는데 대체 여기가 어딜까요?","JPN":"ハハ……ところで、私も気になることがあるんですが、ここはいったいどこでしょう？","ENG":"Hah hah... I've got a question, too. Where is this place?","TWN":"哈哈……那個，我有件好奇的事情，我現在到底在什麼地方？"},"stage":{"bg":"SUMMER_BEACH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"갑자기 눈 앞이 번쩍하더니...... 여기로 떨어진 것 같은데.","JPN":"急に目の前が光って……ここに落ちたみたいですが。","ENG":"One moment I saw a sudden flash of light, and the next I was here.","TWN":"我眼前好像突然一閃……然後就來到這個地方了。"},"stage":{"bg":"SUMMER_BEACH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"ROSARIA_FALLEN_SUMMER_NULL","text":{"KOREA":"흠, 간단히 설명하면 저 음침한 처녀를 위한 운명의 상대를 불러냈더니 네가 튀어나온 상황이지.","JPN":"ふん、簡単に説明すると、あの陰気な乙女のために運命の相手を呼び出したら、其方が飛び出てきたといった状況じゃ。","ENG":"Hm, to cut a long story short, this gloomy maiden here summoned her soul mate, and you popped out.","TWN":"嗯，簡單說明的話，我為那個陰沉的女孩召喚了命運之人，結果妳就蹦出來了。"},"stage":{"bg":"SUMMER_BEACH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"아하, 그렇군요!","JPN":"あ、そういうことですか！","ENG":"Aha, I see!","TWN":"啊哈，原來如此！"},"stage":{"bg":"SUMMER_BEACH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"뭔가 엄청난 일에 휘말린 것 같긴 하지만 제가 선택됐다는 걸 뭐 어쩌겠어요?","JPN":"何かすごいことに巻き込まれたみたいですが、私が選ばれたのなら仕方ありませんね。","ENG":"So, I've been dragged into something incredible, and there's nothing I can do about that, right?","TWN":"看來我被捲入一件大事中了，但既然被選中，那就沒辦法了。"},"stage":{"bg":"SUMMER_BEACH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"그럼 전 언제쯤 원래 있던 곳으로 돌아갈 수 있을까요?","JPN":"ところで、私はいつ頃元の世界に戻れるんですか？","ENG":"Alright, then when do you think I can go back to where I came from?","TWN":"那我什麼時候可以回到原本的地方？"},"stage":{"bg":"SUMMER_BEACH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"ROSARIA_FALLEN_SUMMER_NULL","text":{"KOREA":"음? 소환 마법의 효과가 떨어지면 자동으로 돌아가게 되어 있다만.","JPN":"うん？　召喚魔法の効果が切れたら、自然に戻るはずじゃが。","ENG":"Mm? You'll go back naturally when the summoning magic wears off.","TWN":"嗯？召喚魔法失效後妳會自動返回。"},"stage":{"bg":"SUMMER_BEACH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_SUMMER_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"ROSARIA_FALLEN_SUMMER_NULL","text":{"KOREA":"뭔가 바쁜 일이라도 있느냐?","JPN":"何か急用でもあるのか？","ENG":"Why, are you busy?","TWN":"妳有什麼急事嗎？"},"stage":{"bg":"SUMMER_BEACH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"사실, 의뢰를 받아서 마을을 습격하는 침식체들을 상대하는 중이었거든요.","JPN":"実は、依頼を受けて街を襲う侵食体を退治している最中でした。","ENG":"Actually, I was in the middle of fighting against C.O.s that had invaded the village.","TWN":"事實上，我剛才接到委託，在和襲擊村莊的侵蝕體戰鬥。"},"stage":{"bg":"SUMMER_BEACH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"제가 갑자기 사라져서 동료가 많이 곤란해 하고 있을 것 같아요.","JPN":"私が急にいなくなって、仲間が困ってると思うんですよ。","ENG":"My teammate might be in trouble because I'm gone.","TWN":"我這樣突然消失，一定會給同伴們添麻煩的。"},"stage":{"bg":"SUMMER_BEACH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"ROSARIA_FALLEN_SUMMER_NULL","text":{"KOREA":"아~ 그런 거라면 걱정 말거라.","JPN":"あ～そのことなら心配いらん。","ENG":"Ah, don't worry.","TWN":"啊～這妳不用擔心。"},"stage":{"bg":"SUMMER_BEACH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_SUMMER_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"ROSARIA_FALLEN_SUMMER_NULL","text":{"KOREA":"모아놓은 제물도 아직 충분하니 그것들도 이곳으로 불러와주지.","JPN":"集めておいた供え物もまだ十分だから、それらもこっちに呼び出してやろう。","ENG":"I still have enough offerings left. I'll bring them here, too.","TWN":"反正祭品還很充足，我把它們也召喚到這裡吧。"},"stage":{"bg":"SUMMER_BEACH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"OGRE1_NPC_NULL_NULL","text":{"KOREA":"(변했다. 환경. 여긴 어디?)","JPN":"(変わった。環境。ここはどこ？)","ENG":"(Different place. Where's this?)","TWN":"（環境，變了。這裡是？）"},"stage":{"bg":"SUMMER_BEACH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_SURPRISE"}}},"sfx":"FX_COMBAT_MONSTER_BEAST_VOICE_36"},{"id":"L39_1","type":"dialog","speaker":"OGRE2_NPC_NULL_NULL","text":{"KOREA":"(저기. 인간 여자...... 잔뜩 있다.)","JPN":"(あそこ。人間の女……いっぱいいる)","ENG":"(There. Human females. Many of them.)","TWN":"（那裡，人類女子……好多。）"},"stage":{"bg":"SUMMER_BEACH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_SURPRISE"}}},"sfx":"FX_COMBAT_MONSTER_BEAST_VOICE_35"},{"id":"L40_1","type":"dialog","speaker":"OGRE1_NPC_NULL_NULL","text":{"KOREA":"(데려간다...... 저 검은머리 여자.)","JPN":"(連れて行く……あの黒髪の女)","ENG":"(I takes that black-haired female.)","TWN":"（帶走……那個黑髮女子。）"},"stage":{"bg":"SUMMER_BEACH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_SURPRISE"}}},"sfx":"FX_COMBAT_MONSTER_BEAST_VOICE_23"},{"id":"L41_1","type":"dialog","speaker":"OGRE2_NPC_NULL_NULL","text":{"KOREA":"(아니다! 내가 가져갈 거다. 검은머리 여자.)","JPN":"(いや！　私が持って行く。黒髪の女)","ENG":"(No way! Mine. That black-haired female.)","TWN":"（不！我要帶她走。黑髮女子。）"},"stage":{"bg":"SUMMER_BEACH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_SURPRISE"}}},"sfx":"FX_COMBAT_MONSTER_BEAST_VOICE_36"},{"id":"L42_1","type":"dialog","speaker":"OGRE1_NPC_NULL_NULL","text":{"KOREA":"(비켜라! 저건 내 거다!)","JPN":"(どけ！　あれは私のものだ！)","ENG":"(Outta the way! That's mines!)","TWN":"（讓開！她是我的！）"},"stage":{"bg":"SUMMER_BEACH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_SURPRISE"}}},"sfx":"FX_COMBAT_MONSTER_BEAST_VOICE_32"},{"id":"L47_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"어라? 얘네들 왜 서로 싸우는 거람?","JPN":"あれ？　この子たち、なんで喧嘩してるんだろう？","ENG":"Err? Why are they fighting each other?","TWN":"咦？它們為什麼自己打起來了？"},"stage":{"bg":"SUMMER_BEACH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L48_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"저기...... 기분 탓인진 모르겠는데, 저것들 날 쳐다보고 있는 것 같은......","JPN":"あの……気のせいかもしれませんが、あいつらが私を見ているような……","ENG":"Erm, maybe I'm imagining this, but it seems they're looking at me...","TWN":"那個……不知道是不是我的錯覺，它們好像一直在盯著我看……"},"stage":{"bg":"SUMMER_BEACH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L5_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"끼아아악! 사람 살려어!","JPN":"きゃああああ！　助けて！","ENG":"Kyaaah! HELP!","TWN":"啊啊啊！救命啊！"},"stage":{"bg":"SUMMER_BEACH","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"ROSARIA_FALLEN_SUMMER_NULL","text":{"KOREA":"아하하하하! 버둥대며 끌려가는 꼴이 우습구나.","JPN":"あはははは！　じたばたして連れて行かれる姿が面白いのう。","ENG":"Ah hah hah hah hah! Look at her, flailing her arms trying to get away from them!","TWN":"啊哈哈哈哈！看她被架走的模樣真好笑。"},"stage":{"bg":"SUMMER_BEACH","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_SUMMER_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"저런. 주인님께서 소환하신 침식체들이 의뢰인을 납치해버렸군요.","JPN":"参りましたね。ご主人様が召喚された侵食体が依頼人を拉致してしまいました。","ENG":"Uh-oh. Mistress, the C.O.s that you summoned have abducted our client.","TWN":"天啊，主人召喚出來的侵蝕體綁架了委託人。"},"stage":{"bg":"SUMMER_BEACH","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROSARIA_FALLEN_SUMMER_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"아무래도 제물로 쓰인 머리카락 때문에 강한 유대가 얽혀버린 듯 합니다만.","JPN":"どうやら供え物に使われた髪の毛のせいで、強力な繋がりができてしまったようです。","ENG":"It seems using her hair as an offering has bound them to her.","TWN":"看來是對於作為祭品的頭髮產生了強大的吸引。"},"stage":{"bg":"SUMMER_BEACH","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROSARIA_FALLEN_SUMMER_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L11_1","type":"dialog","speaker":"ROSARIA_FALLEN_SUMMER_NULL","text":{"KOREA":"뭐, 이런 결말도 썩 괜찮지 않느냐?","JPN":"まぁ、こういう結末もなかなかよいではないか？","ENG":"Well, this is not a bad ending, is it?","TWN":"嗯，這樣的結局好像也不錯吧？"},"stage":{"bg":"SUMMER_BEACH","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROSARIA_FALLEN_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L12_1","type":"dialog","speaker":"ROSARIA_FALLEN_SUMMER_NULL","text":{"KOREA":"인간과 침식체 사이에 로맨스가 있으면 안 된다는 법도 없으니 말이지.","JPN":"人間と侵食体の間に愛が生まれることもあるのじゃ。","ENG":"No one says humans can't have a romantic relationship with C.O.s.","TWN":"沒有人規定人類和侵蝕體之間是不能產生愛情啊。"},"stage":{"bg":"SUMMER_BEACH","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROSARIA_FALLEN_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L13_1","type":"dialog","speaker":"YUMA_FALLEN_NULL_NULL","text":{"KOREA":"그런데, 저렇게 도망가버리면 의뢰금을 못 받는 거 아닌가?","JPN":"でもさ、逃げられちまったら依頼金はもらえないんじゃ？","ENG":"But if they take her away, who's going to pay us?","TWN":"但是，如果就這麼放她走，那不是就拿不到委託金了嗎？"},"stage":{"bg":"SUMMER_BEACH","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROSARIA_FALLEN_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L14_1","type":"dialog","speaker":"ROSARIA_FALLEN_SUMMER_NULL","text":{"KOREA":"아.","JPN":"あ。","ENG":"Oh.","TWN":"啊。"},"stage":{"bg":"SUMMER_BEACH","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROSARIA_FALLEN_SUMMER_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_SURPRISE"}}}}]`);export{e as default};